import React, { useState, useEffect } from "react";
import axios from "axios";

const AdminDashboard = () => {
  const [title, setTitle] = useState("");
  const [image, setImage] = useState(null);
  const [categoryId, setCategoryId] = useState("");
  const [categories, setCategories] = useState([]);
  const [message, setMessage] = useState("");

  // ✅ Fetch categories from backend
  useEffect(() => {
    const fetchCategories = async () => {
      try {
        const res = await axios.get("http://localhost:5000/api/categories"); // New endpoint
        setCategories(res.data);
      } catch (error) {
        console.error("Failed to fetch categories", error);
      }
    };
    fetchCategories();
  }, []);

  // ✅ Handle file selection
  const handleFileChange = (e) => {
    setImage(e.target.files[0]);
  };

  // ✅ Upload image function
  const handleUpload = async () => {
    if (!title || !image || !categoryId) {
      setMessage("Please fill in all fields and select a category.");
      return;
    }

    const formData = new FormData();
    formData.append("title", title);
    formData.append("image", image);
    formData.append("categoryId", categoryId); // ✅ This is what you asked

    try {
      await axios.post("http://localhost:5000/api/gallery/upload", formData, {
        headers: { "Content-Type": "multipart/form-data" },
      });
      setMessage("✅ Image uploaded successfully!");
      setTitle("");
      setImage(null);
      setCategoryId("");
    } catch (error) {
      setMessage("❌ Upload failed. Try again.");
    }
  };

  return (
    <div className="container mx-auto p-6">
      <h1 className="text-3xl font-bold mb-4">📸 Admin Dashboard</h1>

      <div className="bg-white p-6 rounded-lg shadow-md">
        <input
          type="text"
          placeholder="Image Title"
          className="p-2 border rounded w-full mb-3"
          value={title}
          onChange={(e) => setTitle(e.target.value)}
        />

        <select
          className="p-2 border rounded w-full mb-3"
          value={categoryId}
          onChange={(e) => setCategoryId(e.target.value)}
        >
          <option value="">Select a category</option>
          {categories.map((cat) => (
            <option key={cat.id} value={cat.id}>
              {cat.name}
            </option>
          ))}
        </select>

        <input
          type="file"
          className="p-2 border rounded w-full mb-3"
          onChange={handleFileChange}
        />

        <button
          onClick={handleUpload}
          className="w-full bg-blue-600 text-white px-4 py-2 rounded hover:bg-blue-700 transition"
        >
          Upload Image
        </button>

        {message && <p className="mt-4 text-center font-medium">{message}</p>}
      </div>
    </div>
  );
};

export default AdminDashboard;
